import{c as a,Q as i,j as t,m as o}from"./chunks/framework.rlpw0eGz.js";const p=JSON.parse('{"title":"🛠️ Windows Tweaks & Optimizations Guide","description":"","frontmatter":{},"headers":[],"relativePath":"TWEAKS.md","filePath":"TWEAKS.md"}'),s={name:"TWEAKS.md"};function r(n,e,l,c,d,g){return i(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="🛠️-windows-tweaks-optimizations-guide" tabindex="-1">🛠️ Windows Tweaks &amp; Optimizations Guide <a class="header-anchor" href="#🛠️-windows-tweaks-optimizations-guide" aria-label="Permalink to &quot;🛠️ Windows Tweaks &amp; Optimizations Guide&quot;">​</a></h1><p>This document provides a highly detailed, comprehensive guide to all system modifications, registry tweaks, and shell scripts located in the <code>Tweaks/</code> directory. These configurations are designed to optimize Windows 10 &amp; 11 for maximum responsiveness, privacy, and gaming efficiency. <strong>All PowerShell scripts in this suite support zero-prompt, unattended execution simply by appending the <code>-Force</code> argument.</strong></p><hr><h2 id="📂-folder-directory-structure" tabindex="-1">📂 Folder Directory Structure <a class="header-anchor" href="#📂-folder-directory-structure" aria-label="Permalink to &quot;📂 Folder Directory Structure&quot;">​</a></h2><p>The <code>Tweaks/</code> directory is organized into functional categories to allow targeted optimizations:</p><ol><li><a href="#1-appearance-tweaks"><strong>Appearance</strong></a>: Interface adjustments, themes, and Cortana.</li><li><a href="#2-background-tweaks"><strong>Background</strong></a>: Power and execution control for background tasks.</li><li><a href="#3-browser-tweaks"><strong>Browser</strong></a>: Optimizing Microsoft Edge and disabling browser preloads.</li><li><a href="#4-display-tweaks"><strong>Display</strong></a>: Custom GPU assignments, Auto SR, HDR, and Windowed Optimizations.</li><li><a href="#5-gaming-tweaks"><strong>Gaming</strong></a>: Windows Game Mode configurations.</li><li><a href="#6-network-tweaks"><strong>Network</strong></a>: Delivery Optimization bandwidth capping and P2P updates.</li><li><a href="#7-privacy-tweaks"><strong>Privacy</strong></a>: Core application permissions lockdowns.</li><li><a href="#8-recursos-resources-standard-tweaks"><strong>Recursos &amp; Resources</strong></a>: Hardware priority tweaks, mitigations, custom power plans, SSD tunings, RAM cleaners, and services.</li><li><a href="#9-startup-tweaks"><strong>Startup</strong></a>: Trimming auto-start software.</li><li><a href="#10-storage-tweaks"><strong>Storage</strong></a>: Safe temporary folder cleaners and Storage Sense toggles.</li><li><a href="#11-storage-aggressive-tweaks"><strong>Storage-Aggressive</strong></a>: System component store and WinSXS cleanups via DISM.</li><li><a href="#12-troubleshooting-tweaks"><strong>Troubleshooting</strong></a>: Diagnostic Clean Boot management.</li><li><a href="#13-wpf-dashboard-walkthrough"><strong>WPF Dashboard Walkthrough</strong></a>: The main interactive control suite.</li></ol><hr><h2 id="_1-appearance-tweaks" tabindex="-1">1. Appearance Tweaks <a class="header-anchor" href="#_1-appearance-tweaks" aria-label="Permalink to &quot;1. Appearance Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Appearance/</code></li><li><strong>Purpose</strong>: Disables taxing visual transitions and unnecessary system components to free up CPU and GPU cycles on older systems.</li></ul><h3 id="available-registry-tweaks" tabindex="-1">Available Registry Tweaks <a class="header-anchor" href="#available-registry-tweaks" aria-label="Permalink to &quot;Available Registry Tweaks&quot;">​</a></h3><ul><li><code>Dark Theme.reg</code> / <code>Light Theme.reg</code>: Swaps the Windows system and app themes between dark and light modes.</li><li><code>Disable Transparency.reg</code> / <code>Enable Transparency.reg</code>: Turns off transparency effects on the taskbar, start menu, and action center. Disabling transparency significantly reduces GPU load in windowed modes.</li><li><code>Disable Action Center.reg</code> / <code>Enable Action Center.reg</code>: Deactivates the system notifications tray.</li><li><code>Disable Cortana.reg</code> / <code>Enable Cortana.reg</code>: Fully blocks the Cortana digital assistant search indexing and background services.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Disabling transparency and transitions is highly recommended for legacy systems with integrated graphics cards (such as Intel HD Graphics) to prevent interface stuttering.</p></div><hr><h2 id="_2-background-tweaks" tabindex="-1">2. Background Tweaks <a class="header-anchor" href="#_2-background-tweaks" aria-label="Permalink to &quot;2. Background Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Background/</code></li><li><strong>Purpose</strong>: Restricts system processes from spinning up background activities when not in use.</li></ul><h3 id="active-utility" tabindex="-1">Active Utility <a class="header-anchor" href="#active-utility" aria-label="Permalink to &quot;Active Utility&quot;">​</a></h3><ul><li><code>Manage Background Apps.ps1</code>: A PowerShell script that configures group policies and registry flags to stop Microsoft Store applications from executing background loops when closed.</li><li><strong>Registry Affected</strong>: <code>HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\BackgroundAccessApplications</code><code>GlobalUserDisabled = 1</code></li></ul><hr><h2 id="_3-browser-tweaks" tabindex="-1">3. Browser Tweaks <a class="header-anchor" href="#_3-browser-tweaks" aria-label="Permalink to &quot;3. Browser Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Browser/</code></li><li><strong>Purpose</strong>: Prevents telemetry and keeps the Edge browser from eating up memory behind the scenes.</li></ul><h3 id="available-registry-tweaks-1" tabindex="-1">Available Registry Tweaks <a class="header-anchor" href="#available-registry-tweaks-1" aria-label="Permalink to &quot;Available Registry Tweaks&quot;">​</a></h3><ul><li><code>Configure Edge Performance.reg</code>: Stops Microsoft Edge from running background extensions and preloading tabs during startup. It also disables built-in shopping helpers and diagnostic tracking.</li><li><code>Revert Edge Performance (Restore).reg</code>: Restores default Microsoft Edge preloading features.</li></ul><hr><h2 id="_4-display-tweaks" tabindex="-1">4. Display Tweaks <a class="header-anchor" href="#_4-display-tweaks" aria-label="Permalink to &quot;4. Display Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Display/</code></li><li><strong>Purpose</strong>: Minimizes graphics latency, configures high-refresh layouts, and guides super-resolution setup.</li></ul><h3 id="components" tabindex="-1">Components <a class="header-anchor" href="#components" aria-label="Permalink to &quot;Components&quot;">​</a></h3><ul><li><code>Enable Windowed Game Optimizations.reg</code> / <code>Disable Windowed Game Optimizations (Restore).reg</code>: Enables flip model presentation for windowed DirectX 10/11 games, improving latency and unlocking features like Auto HDR.</li><li><code>Manage GPU Preference.ps1</code>: Automates setting specific gaming binaries to &quot;High Performance&quot; GPU preference via Windows Graphics settings.</li><li><code>Open Graphics Settings.bat</code>: Quick launcher to open the Windows 10/11 graphics properties control directly.</li><li><code>Auto SR Settings Guide.txt</code> (Automatic Super Resolution): Setup manual detailing hardware requirements (Copilot+ PCs, Snapdragon processors) and system settings for AI-powered game upscaling.</li><li><code>HDR Settings &amp; Keyboard Shortcut.txt</code>: Notes on enabling Windows HDR and using <code>Win + Alt + B</code> to instantly toggle HDR on/off to avoid washed-out colors on standard desktops.</li></ul><hr><h2 id="_5-gaming-tweaks" tabindex="-1">5. Gaming Tweaks <a class="header-anchor" href="#_5-gaming-tweaks" aria-label="Permalink to &quot;5. Gaming Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Gaming/</code></li><li><strong>Purpose</strong>: Optimizes OS process scheduling for active full-screen video games.</li></ul><h3 id="available-registry-tweaks-2" tabindex="-1">Available Registry Tweaks <a class="header-anchor" href="#available-registry-tweaks-2" aria-label="Permalink to &quot;Available Registry Tweaks&quot;">​</a></h3><ul><li><code>Enable Game Mode.reg</code> / <code>Disable Game Mode (Restore).reg</code>: Toggles Windows Game Mode. When active, it prioritizes CPU resources for the foreground game, minimizes background notification interruptions, and suspends background updates during play.</li></ul><hr><h2 id="_6-network-tweaks" tabindex="-1">6. Network Tweaks <a class="header-anchor" href="#_6-network-tweaks" aria-label="Permalink to &quot;6. Network Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Network/</code></li><li><strong>Purpose</strong>: Frees up local network bandwidth and stops background update uploads.</li></ul><h3 id="available-registry-tweaks-3" tabindex="-1">Available Registry Tweaks <a class="header-anchor" href="#available-registry-tweaks-3" aria-label="Permalink to &quot;Available Registry Tweaks&quot;">​</a></h3><ul><li><code>Cap Delivery Optimization Bandwidth.reg</code> / <code>Remove Bandwidth Caps (Restore).reg</code>: Caps background download/upload bandwidth used for Windows Update delivery optimizations to prevent network spikes while gaming.</li><li><code>Disable Peer to Peer Updates.reg</code> / <code>Enable Peer to Peer Updates (Restore).reg</code>: Prevents Windows from uploading updates to other PCs on the internet (which severely chokes home upload bandwidth).</li></ul><hr><h2 id="_7-privacy-tweaks" tabindex="-1">7. Privacy Tweaks <a class="header-anchor" href="#_7-privacy-tweaks" aria-label="Permalink to &quot;7. Privacy Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Privacy/</code></li><li><strong>Purpose</strong>: System-wide blockades to prevent background telemetry transmission and device snooping.</li></ul><h3 id="available-registry-tweaks-4" tabindex="-1">Available Registry Tweaks <a class="header-anchor" href="#available-registry-tweaks-4" aria-label="Permalink to &quot;Available Registry Tweaks&quot;">​</a></h3><ul><li><code>Disable App Metadata Access.reg</code> / <code>Enable App Metadata Access.reg</code>: Stops Windows from scanning app configurations.</li><li><code>Disable Camera.reg</code> / <code>Enable Camera.reg</code>: Blocks camera sensor access for standard desktop/UWP apps globally.</li><li><code>Disable Location.reg</code> / <code>Enable Location.reg</code>: Deactivates Windows Location tracking services.</li><li><code>Disable Microphone.reg</code> / <code>Enable Microphone.reg</code>: Turns off microphone capture access globally.</li><li><code>Disable Notifications.reg</code> / <code>Enable Notifications.reg</code>: Blocks UWP system toast notification popups.</li></ul><hr><h2 id="_8-recursos-resources-standard-tweaks" tabindex="-1">8. Recursos &amp; Resources (Standard Tweaks) <a class="header-anchor" href="#_8-recursos-resources-standard-tweaks" aria-label="Permalink to &quot;8. Recursos &amp; Resources (Standard Tweaks)&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Recursos/</code> &amp; <code>Tweaks/Resources/</code></li><li><strong>Purpose</strong>: The traditional performance tweaks folder.</li></ul><h3 id="key-components" tabindex="-1">Key Components <a class="header-anchor" href="#key-components" aria-label="Permalink to &quot;Key Components&quot;">​</a></h3><h4 id="cpu-priorities" tabindex="-1">CPU Priorities <a class="header-anchor" href="#cpu-priorities" aria-label="Permalink to &quot;CPU Priorities&quot;">​</a></h4><ul><li><code>Games Priority.reg</code>: Modifies the Multimedia Class Scheduler (MMCSS) to allocate up to 80% CPU resources directly to active games and applications.</li><li><code>Windows Priority.reg</code> / <code>Revert Changes.reg</code>: Restores balanced desktop thread priority parameters.</li><li><strong>Registry Paths Modifed</strong>: <code>HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Multimedia\\SystemProfile\\Tasks\\Games</code></li></ul><h4 id="cpu-mitigations" tabindex="-1">CPU Mitigations <a class="header-anchor" href="#cpu-mitigations" aria-label="Permalink to &quot;CPU Mitigations&quot;">​</a></h4><ul><li><code>InSpectre.exe</code>: A lightweight diagnostic utility that allows the safe enabling/disabling of Meltdown and Spectre hardware mitigations. <ul><li><em>Mitigations OFF</em>: Restores lost CPU performance (highly noticeable on 8th Gen Intel processors and older), but exposes the system to theoretical security exploits.</li><li><em>Mitigations ON</em>: Maximum security configuration, but reduces disk read/write throughput and raw execution speeds.</li></ul></li></ul><h4 id="cpu-power-plans" tabindex="-1">CPU Power Plans <a class="header-anchor" href="#cpu-power-plans" aria-label="Permalink to &quot;CPU Power Plans&quot;">​</a></h4><ul><li><code>QuickCPU.pow</code>: A custom-engineered system power configuration optimized to minimize CPU core parking, maintain high frequency scales longer, and disable standard power savings when processing active loads.</li><li><code>Aplicar.bat</code> / <code>Apply.bat</code>: Shell scripts to import and active the custom power plan via command line.<div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">powercfg </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">import </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;%~dp0QuickCPU.pow&quot;</span></span></code></pre></div></li></ul><h4 id="ssd-optimizations" tabindex="-1">SSD Optimizations <a class="header-anchor" href="#ssd-optimizations" aria-label="Permalink to &quot;SSD Optimizations&quot;">​</a></h4><ul><li><code>Optimizar SSD.reg</code> / <code>Revert Changes.reg</code>: Applies SSD-specific settings: <ul><li>Enables <strong>TRIM</strong> to ensure even wear on NAND flash cells.</li><li>Disables <strong>Superfetch / Prefetch</strong> (redundant on solid-state drives, saves excess disk write cycles).</li><li>Optimizes standard disk write caching values.</li></ul></li></ul><h4 id="memory-reduction" tabindex="-1">Memory Reduction <a class="header-anchor" href="#memory-reduction" aria-label="Permalink to &quot;Memory Reduction&quot;">​</a></h4><ul><li><code>Mem Reduct RAM</code> (Portable): A light memory management utility. <ul><li>Cleans system caches, working sets, and pagefiles on command.</li><li>Configures cleanups when memory saturation crosses specific benchmarks (e.g., 85%).</li><li>Essential for legacy hardware configurations equipped with less than 8GB of RAM.</li></ul></li></ul><h4 id="ram-compression" tabindex="-1">RAM Compression <a class="header-anchor" href="#ram-compression" aria-label="Permalink to &quot;RAM Compression&quot;">​</a></h4><ul><li><code>Disable Compression.cmd</code> / <code>Revert Changes.bat</code>: Toggles Windows virtual memory compression. <ul><li><em>Compression Disabled</em>: Eliminates CPU processing latency associated with compressing inactive RAM pages. Best for systems with 16GB+ RAM.</li><li><em>Compression Enabled</em>: Compress pages to conserve capacity. Recommended for systems with 4GB/8GB RAM to prevent immediate swapfile thrashing on slow HDDs.</li></ul></li></ul><h4 id="system-services" tabindex="-1">System Services <a class="header-anchor" href="#system-services" aria-label="Permalink to &quot;System Services&quot;">​</a></h4><ul><li><code>Optimize Services.reg</code>: Disables or sets to Manual a wide array of legacy, enterprise, and telemetry-related background services (e.g., Bluetooth, print spooling if unused, faxing, remote registries).</li></ul><h4 id="telemetry-data-collection" tabindex="-1">Telemetry &amp; Data Collection <a class="header-anchor" href="#telemetry-data-collection" aria-label="Permalink to &quot;Telemetry &amp; Data Collection&quot;">​</a></h4><ul><li><code>Disable Telemetry.reg</code>: Blocks telemetry routines, CEIP diagnostic collection, and Windows feedback prompts.</li></ul><hr><h2 id="_9-startup-tweaks" tabindex="-1">9. Startup Tweaks <a class="header-anchor" href="#_9-startup-tweaks" aria-label="Permalink to &quot;9. Startup Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Startup/</code></li><li><strong>Purpose</strong>: Manages software launch profiles during system startup.</li></ul><h3 id="active-utility-1" tabindex="-1">Active Utility <a class="header-anchor" href="#active-utility-1" aria-label="Permalink to &quot;Active Utility&quot;">​</a></h3><ul><li><code>Manage Startup Apps.ps1</code>: PowerShell script to scan, identify, and disable heavy third-party auto-starting applications in registry locations like: <code>HKLM\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code><code>HKCU\\Software\\Microsoft\\Windows\\CurrentVersion\\Run</code></li></ul><hr><h2 id="_10-storage-tweaks" tabindex="-1">10. Storage Tweaks <a class="header-anchor" href="#_10-storage-tweaks" aria-label="Permalink to &quot;10. Storage Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Storage/</code></li><li><strong>Purpose</strong>: Automates standard garbage collection and frees up wasted gigabytes.</li></ul><h3 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><ul><li><code>Enable Storage Sense.reg</code> / <code>Disable Storage Sense (Restore).reg</code>: Toggles Windows Storage Sense utility, which automatically deletes temporary files, clears the Recycle Bin, and cleans downloaded items at set intervals.</li><li><code>Safe Temporary Cleanup.bat</code>: A non-destructive shell script that purges the following cache directories safely: <ul><li><code>%temp%</code> (User Temporary directory)</li><li><code>C:\\Windows\\Temp</code> (System Temporary directory)</li><li><code>C:\\Windows\\Prefetch</code> (Prefetch system files)</li></ul></li></ul><hr><h2 id="_11-storage-aggressive-tweaks" tabindex="-1">11. Storage-Aggressive Tweaks <a class="header-anchor" href="#_11-storage-aggressive-tweaks" aria-label="Permalink to &quot;11. Storage-Aggressive Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Storage-Aggressive/</code></li><li><strong>Purpose</strong>: Sweeps system files and component stores for deeper debloating.</li></ul><h3 id="active-utility-2" tabindex="-1">Active Utility <a class="header-anchor" href="#active-utility-2" aria-label="Permalink to &quot;Active Utility&quot;">​</a></h3><ul><li><code>Deep Component Cleanup (Aggressive).bat</code>: A script that must be run as Administrator. It uses the Deployment Image Servicing and Management (DISM) tool to purge superseded system files, unused component packages, and legacy update backups from the <code>WinSXS</code> folder.</li><li><strong>Commands executed</strong>:<div class="language-cmd vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cmd</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Dism.exe /online /Cleanup</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Image /StartComponentCleanup /ResetBase</span></span></code></pre></div><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Running this aggressive component store cleanup removes old update uninstall files permanently. You will not be able to uninstall current updates once completed.</p></div></li></ul><hr><h2 id="_12-troubleshooting-tweaks" tabindex="-1">12. Troubleshooting Tweaks <a class="header-anchor" href="#_12-troubleshooting-tweaks" aria-label="Permalink to &quot;12. Troubleshooting Tweaks&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Tweaks/Troubleshooting/</code></li><li><strong>Purpose</strong>: Restores system variables back to isolated baseline states.</li></ul><h3 id="tools-1" tabindex="-1">Tools <a class="header-anchor" href="#tools-1" aria-label="Permalink to &quot;Tools&quot;">​</a></h3><ul><li><code>Clean Boot Manager.ps1</code>: A PowerShell diagnostic utility that disables all non-Microsoft startup applications and services, creating an isolated boot profile. Extremely useful for identifying game-crashing software components or overlay conflicts.</li></ul><hr><h2 id="_13-wpf-dashboard-walkthrough" tabindex="-1">13. WPF Dashboard Walkthrough <a class="header-anchor" href="#_13-wpf-dashboard-walkthrough" aria-label="Permalink to &quot;13. WPF Dashboard Walkthrough&quot;">​</a></h2><ul><li><strong>Path</strong>: <code>Start.bat</code> -&gt; <code>Launch_Dashboard.ps1</code></li><li><strong>Purpose</strong>: The central menu interface.</li></ul><p>The framework now features a stunning native PowerShell + WPF XAML graphical dashboard. Double-click <code>Start.bat</code> to launch it. The dashboard consists of multiple tabs:</p><ol><li><strong>Optimization Profiles</strong>: <ul><li><strong>Max Performance Mode</strong>: Targets the absolute lowest DPC latency and highest thread priorities for elite gamers.</li><li><strong>Balanced Creator Mode</strong>: Optimizes Windows Explorer and removes bloatware without disabling Windows Updates or breaking creative apps.</li><li><strong>Enterprise Compliance Mode</strong>: Reverts the OS into a highly secure, privacy-hardened state for corporate usage.</li></ul></li><li><strong>Observability Telemetry</strong>: A real-time dashboard leveraging high-speed <code>.NET Diagnostics</code> to monitor DPC latency proxy speeds, Available RAM, Uptime, and Active Process Counts.</li><li><strong>Rollback Engine</strong>: Safely displays your JSON snapshot history, allowing you to instantly revert any registry/service modifications with a single click. <ul><li>Reducing visual effects quality parameters.</li><li>Applying MMCSS gaming priority.</li><li>Setting active game processes (like CS:GO, CS2, Fortnite, Minecraft, GTA V) to high performance CPU scheduling execution properties.</li></ul></li><li><strong>Create Restore Point</strong>: Highly recommended first step. It runs PowerShell to enable system restores and establish a safe baseline bookmark named &quot;Optimizer Script&quot;.</li><li><strong>Delete Temporary Files</strong>: Automatically cleans the user temp, system temp, and prefetch storage directories.</li><li><strong>Disable Windows Defender</strong>: Menu options to switch active Windows Defender, Security Health, and real-time monitoring services off.</li><li><strong>Disable Windows Update</strong>: Menu to pause and stop update schedulers and update self-healing dll dependencies.</li><li><strong>About the Optimizer</strong>: Credit listing and licensing summaries.</li></ol><hr><h2 id="💡-summary-recommendations-by-use-case" tabindex="-1">💡 Summary Recommendations by Use Case <a class="header-anchor" href="#💡-summary-recommendations-by-use-case" aria-label="Permalink to &quot;💡 Summary Recommendations by Use Case&quot;">​</a></h2><h3 id="🎮-gaming-optimization" tabindex="-1">🎮 Gaming Optimization <a class="header-anchor" href="#🎮-gaming-optimization" aria-label="Permalink to &quot;🎮 Gaming Optimization&quot;">​</a></h3><ul><li>Create a restore point (Menu Option 3).</li><li>Run Option 1 (Apply Recommended Optimizations) to reduce MMCSS process delays and optimize service responsiveness.</li><li>Import <code>Tweaks/Recursos/CPU Power Plan/QuickCPU.pow</code> and active the profile.</li><li>Apply <code>Tweaks/Display/Enable Windowed Game Optimizations.reg</code>.</li><li>Verify sensor temperatures using diagnostics inside <a href="./HARDWARE.html"><strong>Hardware Monitoring</strong></a>.</li></ul><h3 id="💻-legacy-low-end-hardware-8gb-ram" tabindex="-1">💻 Legacy / Low-End Hardware (&lt;8GB RAM) <a class="header-anchor" href="#💻-legacy-low-end-hardware-8gb-ram" aria-label="Permalink to &quot;💻 Legacy / Low-End Hardware (&lt;8GB RAM)&quot;">​</a></h3><ul><li>Apply <code>Tweaks/Appearance/Disable Transparency.reg</code> to lighten graphics processor loads.</li><li>Keep Virtual RAM Compression <strong>Enabled</strong> (<code>Tweaks/Recursos/RAM Compression/Revert Changes.bat</code>) to prevent early HDD paging.</li><li>Run <code>Tweaks/Recursos/Mem Reduct RAM/memreduct.exe</code> to manage memory usage.</li><li>Apply services debloating via <code>Tweaks/Recursos/Services/Optimize Services.reg</code>.</li></ul><h3 id="🔒-maximum-system-privacy" tabindex="-1">🔒 Maximum System Privacy <a class="header-anchor" href="#🔒-maximum-system-privacy" aria-label="Permalink to &quot;🔒 Maximum System Privacy&quot;">​</a></h3><ul><li>Apply <code>Tweaks/Recursos/Telemetry/Disable Telemetry.reg</code> and <code>Tweaks/Privacy/Disable App Metadata Access.reg</code>.</li><li>Run <code>Tweaks/Background/Manage Background Apps.ps1</code> to stop closed applications from executing in the background.</li><li>Lock application permissions using the scripts in <code>Tweaks/Privacy/</code>.</li><li>Consult the <a href="./BROWSERS.html"><strong>Web Browsers Guide</strong></a> to choose privacy-respecting navigation software.</li></ul>',95)])])}const h=a(s,[["render",r]]);export{p as __pageData,h as default};
